import BackToHome from "@/components/common/BackToHome";
import Container from "@/components/common/Container";
import { fetchData } from "@/lib/api";
import { Product } from "@/types/type";
import Image from "next/image";
import React from "react";

const SingleProductPage = async ({
  params,
}: {
  params: Promise<{ id: string }>;
}) => {
  const { id } = await params;
  const product: Product = await fetchData(`/products/${id}`);

  const discountedPrice =
    product?.price * (1 - product?.discountPercentage / 100);

  if (!product) {
    return (
      <div className="min-h-[50vh] flex flex-col gap-2 items-center justify-center p-10">
        <h2 className="text-lg">
          No products found with <span className=" font-medium">#id</span>{" "}
          <span className="font-semibold text-babyshopSky underline">{id}</span>
        </h2>
        <BackToHome />
      </div>
    );
  }

  return (
    <div className="pt-5 mx-4">
      <Container className="bg-babyshopWhite shadow-babyshopBlack/10 shadow-sm border border-babyshopTextLight/30 rounded-xl grid grid-cols-1 md:grid-cols-2 gap-10 p-5 md:p-10">
        <div>
          <Image
            src={product?.image}
            alt="productImage"
            width={500}
            height={500}
          />
        </div>
        <div>description</div>
      </Container>
    </div>
  );
};

export default SingleProductPage;
